global hg_cmd_gridstats, hg_cmd_gridprune

; Align stack for C after setup_cmd (entry rsp%16==0 from asm caller).
%macro CMD_ALIGN 0
    sub rsp, 8
%endmacro
%macro CMD_UNALIGN 0
    add rsp, 8
%endmacro

; Parse first word from rdx into [rsp+16] (40 bytes). Returns rax=1 if non-empty.
parse_word_h:
    push rbx
    push r12
    sub rsp, 8
    mov r12, rdx
    test r12, r12
    jz .empty
    mov rdi, r12
    call skip_spaces
    mov r12, rax
    cmp byte [r12], 0
    je .empty
    xor ebx, ebx
.loop:
    movzx eax, byte [r12 + rbx]
    test al, al
    jz .done
    cmp al, ' '
    je .done
    cmp ebx, 38
    jge .done
    mov [rsp + 16 + rbx], al
    inc ebx
    jmp .loop
.done:
    mov byte [rsp + 16 + rbx], 0
    mov eax, 1
    jmp .out
.empty:
    xor eax, eax
.out:
    add rsp, 8
    pop r12
    pop rbx
    ret


; --- free -------------------------------------------------------------------
hg_cmd_free:
    call setup_cmd
    CMD_ALIGN
    mov rax, [r12 + SESSION_ROOM]
    cmp rax, ROOM_HOLDING_PIT
    je .pit
    cmp rax, ROOM_CELLS
    je .cells
    mov rdi, r12
    lea rsi, [rel sp2_free_none]
    call queue_line_h
    CMD_UNALIGN
    ret
.pit:
    mov rdi, r12
    lea rsi, [rel sp2_antidote]
    call inv_find_slot
    test eax, eax
    jns .have_vial
    mov rdi, r12
    lea rsi, [rel sp2_antidote]
    call inv_add_internal
    add qword [r12 + SESSION_MORALITY], 12
    lea rdi, [r12 + SESSION_LAST_FREED]
    cmp byte [rdi], 0
    jne .pit_deed
    lea rsi, [rel sp2_mira]
    mov edx, 40
    call strncpy wrt ..plt
.pit_deed:
    lea rdi, [r12 + SESSION_NAME]
    mov esi, DEED_FREED
    call hg_add_deed_h
    sub rsp, 400
    mov rdi, r12
    call hg_now_ms wrt ..plt
    mov r14, rax
    lea rdi, [rel sp2_basalt]
    lea rsi, [rel sp2_mira]
    lea rdx, [r12 + SESSION_NAME]
    mov rcx, r14
    call hg_grid_record_rescued wrt ..plt
    mov rdi, rsp
    mov esi, 320
    lea rdx, [rel sp2_free_pit]
    lea rcx, [rel sp2_mira]
    xor eax, eax
    call snprintf wrt ..plt
    mov rdi, r12
    mov rsi, rsp
    call queue_line_h
    lea rdi, [rsp + 160]
    mov esi, 80
    lea rdx, [r12 + SESSION_NAME]
    call hg_json_escape wrt ..plt
    lea rdi, [rsp + 240]
    mov esi, 80
    lea rdx, [rel sp2_mira]
    call hg_json_escape wrt ..plt
    lea rdi, [rsp + 320]
    mov esi, 80
    lea rdx, [rel sp2_rescued_one]
    lea rcx, [rsp + 160]
    lea r8, [rsp + 240]
    xor eax, eax
    call snprintf wrt ..plt
    mov rdi, r12
    lea rsi, [rsp + 320]
    call queue_cstr_h
    xor edi, edi
    xor esi, esi
    call hg_grid_shift_tide wrt ..plt
    mov rdi, r12
    call hg_emit_affects_now wrt ..plt
    mov rdi, r12
    call hg_store_save wrt ..plt
    add rsp, 400
    CMD_UNALIGN
    ret
.have_vial:
    mov rdi, r12
    lea rsi, [rel sp2_free_have]
    call queue_line_h
    CMD_UNALIGN
    ret
.cells:
    mov rdi, r12
    call hg_now_ms wrt ..plt
    mov r14, rax
    call hg_cells_ready_at_get
    cmp rax, r14
    jg .cells_empty
    mov rdi, r14
    add rdi, 3600000
    call hg_cells_ready_at_set
    lea rdi, [r12 + SESSION_LAST_FREED]
    cmp byte [rdi], 0
    jne .cells_deed
    lea rsi, [rel sp2_rook]
    mov edx, 40
    call strncpy wrt ..plt
.cells_deed:
    lea rdi, [r12 + SESSION_NAME]
    mov esi, DEED_FREED
    call hg_add_deed_h
    lea rdi, [rel sp2_basalt]
    lea rsi, [rel sp2_rook]
    lea rdx, [r12 + SESSION_NAME]
    mov rcx, r14
    call hg_grid_record_rescued wrt ..plt
    lea rdi, [rel sp2_basalt]
    lea rsi, [rel sp2_sable]
    lea rdx, [r12 + SESSION_NAME]
    mov rcx, r14
    call hg_grid_record_rescued wrt ..plt
    add qword [r12 + SESSION_MORALITY], 15
    mov rdi, r12
    lea rsi, [rel sp2_free_cells]
    call queue_cstr_h
    ; esc@0(80) evt@80(160) = 240; keep inside the frame (old +240/80 smashed ret)
    sub rsp, 240
    mov rdi, rsp
    mov esi, 80
    lea rdx, [r12 + SESSION_NAME]
    call hg_json_escape wrt ..plt
    lea rdi, [rsp + 80]
    mov esi, 160
    lea rdx, [rel sp2_rescued_two]
    mov rcx, rsp
    lea r8, [rel sp2_rook]
    lea r9, [rel sp2_sable]
    xor eax, eax
    call snprintf wrt ..plt
    mov rdi, r12
    lea rsi, [rsp + 80]
    call queue_cstr_h
    mov rdi, r12
    call hg_emit_affects_now wrt ..plt
    mov rdi, r12
    call hg_store_save wrt ..plt
    add rsp, 240
    CMD_UNALIGN
    ret
.cells_empty:
    mov rdi, r12
    lea rsi, [rel sp2_free_empty]
    call queue_line_h
    CMD_UNALIGN
    ret

; --- gridcast ---------------------------------------------------------------
hg_cmd_gridcast:
    call setup_cmd
    CMD_ALIGN
    mov rdi, rdx
    call skip_spaces
    mov r14, rax
    cmp byte [r14], 0
    je .need
    lea rdi, [r12 + SESSION_NAME]
    mov rsi, r14
    call hg_grid_gridcast wrt ..plt
    test eax, eax
    jnz .fail
    ; r14 still holds the message text (eax is 0 on success)
    sub rsp, 320
    mov rdi, rsp
    mov esi, 280
    lea rdx, [rel sp2_gridcast_prose]
    mov rcx, r14
    xor eax, eax
    call snprintf wrt ..plt
    mov rdi, r12
    mov rsi, rsp
    call queue_line_h
    mov rdi, r12
    mov rsi, r14
    call hg_emit_comm_gridcast_now wrt ..plt
    add rsp, 320
    CMD_UNALIGN
    ret
.need:
    mov rdi, r12
    lea rsi, [rel sp2_gridcast_need]
    call queue_line_h
    CMD_UNALIGN
    ret
.fail:
    mov rdi, r12
    lea rsi, [rel sp2_gridcast_fail]
    call queue_line_h
    CMD_UNALIGN
    ret

