; --- forgive (ledger, morality, deeds, redemption title) --------------------
hg_cmd_forgive:
    call setup_cmd
    CMD_ALIGN
    push rbx
    push r14
    push r15
    sub rsp, 200
    mov rdi, rdx
    test rdi, rdi
    jz .need
    call skip_spaces
    mov r14, rax
    cmp byte [r14], 0
    je .need
    xor ebx, ebx
.pw:
    movzx eax, byte [r14 + rbx]
    test al, al
    jz .pw_done
    cmp al, ' '
    je .pw_done
    cmp ebx, 38
    jge .pw_done
    mov [rsp + rbx], al
    inc ebx
    jmp .pw
.pw_done:
    mov byte [rsp + rbx], 0
    test ebx, ebx
    jz .need
    lea rdi, [rsp]
    lea rsi, [r12 + SESSION_NAME]
    call strcasecmp wrt ..plt
    test eax, eax
    jz .self
    mov rdi, [r12 + SESSION_ROOM]
    lea rsi, [rsp]
    xor edx, edx
    call find_player_prefix
    test rax, rax
    jz .absent
    mov r15, rax
    lea rdi, [r12 + SESSION_NAME]
    lea rsi, [r15 + SESSION_NAME]
    call hg_forgiven_has wrt ..plt
    test eax, eax
    jnz .twice
    cmp qword [r15 + SESSION_ASHSWORN], 0
    jne .marked
    cmp qword [r15 + SESSION_STRAYED], 0
    jne .marked
    lea rdi, [r15 + SESSION_FACTION]
    lea rsi, [rel sp2_front]
    call strcmp wrt ..plt
    test eax, eax
    jz .marked
    mov rax, [r15 + SESSION_MORALITY]
    cmp rax, -50
    jg .unmarked
.marked:
    lea rdi, [r12 + SESSION_NAME]
    lea rsi, [r15 + SESSION_NAME]
    call hg_forgiven_mark wrt ..plt
    lea rdi, [r12 + SESSION_NAME]
    lea rsi, [rel sp2_dforgave]
    call hg_deed_add_str wrt ..plt
    add qword [r15 + SESSION_MORALITY], 5
    add qword [r12 + SESSION_MORALITY], 2
    lea rdi, [rsp + 40]
    mov esi, 160
    lea rdx, [rel sp2_grace]
    lea rcx, [r12 + SESSION_NAME]
    lea r8, [r15 + SESSION_NAME]
    xor eax, eax
    call snprintf wrt ..plt
    mov rdi, [r12 + SESSION_ROOM]
    call hg_room_id_cstr wrt ..plt
    test rax, rax
    jnz .grace_node
    lea rax, [rel sp2_market]
.grace_node:
    mov rdi, rax
    lea rsi, [rel sp2_grace_kind]
    lea rdx, [rsp + 40]
    call hg_grid_record_local_echo wrt ..plt
    cmp qword [r15 + SESSION_ASHSWORN], 0
    jne .ash_path
    cmp qword [r15 + SESSION_STRAYED], 0
    je .plain_path
    cmp qword [r15 + SESSION_REDEEMED], 0
    jne .plain_path
    lea rdi, [r15 + SESSION_FACTION]
    lea rsi, [rel sp2_front]
    call strcmp wrt ..plt
    test eax, eax
    jz .plain_path
    mov qword [r15 + SESSION_REDEEMED], 1
    cmp byte [r15 + SESSION_TITLE], 0
    jne .save_redeem
    lea rdi, [r15 + SESSION_TITLE]
    lea rsi, [rel sp2_returned]
    mov edx, 48
    call strncpy wrt ..plt
    mov byte [r15 + SESSION_TITLE + 47], 0
.save_redeem:
    mov rdi, r15
    call hg_store_save wrt ..plt
    mov rdi, r15
    mov rsi, r12
    call hg_emit_forgiven_redeemed_now wrt ..plt
    jmp .room_announce
.ash_path:
    mov rdi, r15
    mov rsi, r12
    mov edx, 1
    xor ecx, ecx
    call hg_emit_forgiven_target_now wrt ..plt
    jmp .room_announce
.plain_path:
    mov rdi, r15
    mov rsi, r12
    xor edx, edx
    xor ecx, ecx
    call hg_emit_forgiven_target_now wrt ..plt
.room_announce:
    lea rdi, [rsp + 40]
    mov esi, 160
    lea rdx, [rel sp2_forgive_room]
    lea rcx, [r12 + SESSION_NAME]
    lea r8, [r15 + SESSION_NAME]
    xor eax, eax
    call snprintf wrt ..plt
    mov rdi, [r12 + SESSION_ROOM]
    lea rsi, [rsp + 40]
    lea rdx, [r12 + SESSION_NAME]
    call hg_deliver_room wrt ..plt
    lea rdi, [rsp + 40]
    mov esi, 160
    lea rdx, [rel sp2_forgive_you]
    lea rcx, [r15 + SESSION_NAME]
    xor eax, eax
    call snprintf wrt ..plt
    mov rdi, r12
    lea rsi, [rsp + 40]
    call queue_line_h
    mov rdi, r12
    call hg_emit_affects_now wrt ..plt
    add rsp, 200
    pop r15
    pop r14
    pop rbx
    CMD_UNALIGN
    ret
.need:
    mov rdi, r12
    lea rsi, [rel sp2_forgive_need]
    call queue_line_h
    add rsp, 200
    pop r15
    pop r14
    pop rbx
    CMD_UNALIGN
    ret
.self:
    mov rdi, r12
    lea rsi, [rel sp2_forgive_self]
    call queue_line_h
    add rsp, 200
    pop r15
    pop r14
    pop rbx
    CMD_UNALIGN
    ret
.absent:
    lea rdi, [rsp + 40]
    mov esi, 120
    lea rdx, [rel sp2_forgive_absent]
    lea rcx, [rsp]
    xor eax, eax
    call snprintf wrt ..plt
    mov rdi, r12
    lea rsi, [rsp + 40]
    call queue_line_h
    add rsp, 200
    pop r15
    pop r14
    pop rbx
    CMD_UNALIGN
    ret
.twice:
    lea rdi, [rsp + 40]
    mov esi, 160
    lea rdx, [rel sp2_forgive_twice]
    lea rcx, [r15 + SESSION_NAME]
    xor eax, eax
    call snprintf wrt ..plt
    mov rdi, r12
    lea rsi, [rsp + 40]
    call queue_line_h
    add rsp, 200
    pop r15
    pop r14
    pop rbx
    CMD_UNALIGN
    ret
.unmarked:
    lea rdi, [rsp + 40]
    mov esi, 160
    lea rdx, [rel sp2_forgive_unmarked]
    lea rcx, [r15 + SESSION_NAME]
    xor eax, eax
    call snprintf wrt ..plt
    mov rdi, r12
    lea rsi, [rsp + 40]
    call queue_line_h
    add rsp, 200
    pop r15
    pop r14
    pop rbx
    CMD_UNALIGN
    ret

; --- witness (keep fallen memory; roll presentation via format) ------------
hg_cmd_witness:
    call setup_cmd
    CMD_ALIGN
    push rbx
    push r14
    push r15
    ; layout: who[40] @0, fallen[12*128] @64, count@1600,
    ; scratch/escapes @1608 (40+48+40), evt @1744 (280). Frame 2040 (align).
    sub rsp, 2040
    mov byte [rsp], 0
    mov rdi, rdx
    test rdi, rdi
    jz .have_word
    call skip_spaces
    mov r14, rax
    cmp byte [r14], 0
    je .have_word
    xor ebx, ebx
.pw:
    movzx eax, byte [r14 + rbx]
    test al, al
    jz .pw_done
    cmp al, ' '
    je .pw_done
    cmp ebx, 38
    jge .pw_done
    mov [rsp + rbx], al
    inc ebx
    jmp .pw
.pw_done:
    mov byte [rsp + rbx], 0
.have_word:
    mov qword [rsp + 1600], 0
    mov edi, 12
    lea rsi, [rsp + 64]
    mov edx, 12
    lea rcx, [rsp + 1600]
    call hg_grid_recent_fallen wrt ..plt
    cmp byte [rsp], 0
    jne .named
    mov rdi, r12
    call hg_emit_fallen_roll_now wrt ..plt
    jmp .done
.named:
    lea rdi, [rsp]
    lea rsi, [r12 + SESSION_NAME]
    call strcasecmp wrt ..plt
    test eax, eax
    jz .self
    mov r15, [rsp + 1600]
    xor ebx, ebx
    xor r14, r14
.find:
    cmp rbx, r15
    jae .find_done
    imul rax, rbx, 128
    lea rdi, [rsp + 64 + rax + 48]
    lea rsi, [rsp]
    call strcasecmp wrt ..plt
    test eax, eax
    jnz .next
    imul rax, rbx, 128
    lea r14, [rsp + 64 + rax]
    jmp .find_done
.next:
    inc ebx
    jmp .find
.find_done:
    test r14, r14
    jz .absent
    lea rdi, [r12 + SESSION_NAME]
    lea rsi, [r14 + 48]
    call hg_kept_has wrt ..plt
    test eax, eax
    jnz .twice
    lea rdi, [r12 + SESSION_NAME]
    lea rsi, [r14 + 48]
    call hg_kept_mark wrt ..plt
    add qword [r12 + SESSION_MORALITY], 2
    lea rdi, [r12 + SESSION_NAME]
    lea rsi, [rel sp2_dkept]
    call hg_deed_add_str wrt ..plt
    mov rdi, r12
    call hg_store_save wrt ..plt
    lea rdi, [rsp + 1608]
    mov esi, 160
    lea rdx, [rel sp2_vigil_echo]
    lea rcx, [r12 + SESSION_NAME]
    lea r8, [r14 + 48]
    xor eax, eax
    call snprintf wrt ..plt
    mov rdi, [r12 + SESSION_ROOM]
    call hg_room_id_cstr wrt ..plt
    test rax, rax
    jnz .vigil_node
    lea rax, [rel sp2_waystation]
.vigil_node:
    mov rdi, rax
    lea rsi, [rel sp2_vigil_kind]
    lea rdx, [rsp + 1608]
    call hg_grid_record_local_echo wrt ..plt
    lea rdi, [rsp + 1608]
    mov esi, 160
    lea rdx, [rel sp2_witness_prose]
    lea rcx, [r14 + 48]
    xor eax, eax
    call snprintf wrt ..plt
    mov rdi, r12
    lea rsi, [rsp + 1608]
    call queue_line_h
    lea rdi, [rsp + 1608]
    mov esi, 40
    lea rdx, [r14 + 48]
    call hg_json_escape wrt ..plt
    lea rdi, [rsp + 1648]
    mov esi, 48
    lea rdx, [r14]
    call hg_json_escape wrt ..plt
    lea rdi, [rsp + 1696]
    mov esi, 40
    lea rdx, [r14 + 81]
    call hg_json_escape wrt ..plt
    lea rdi, [rsp + 1744]
    mov esi, 280
    lea rdx, [rel sp2_remembrance_evt]
    lea rcx, [rsp + 1608]
    lea r8, [rsp + 1648]
    lea r9, [rsp + 1696]
    xor eax, eax
    call snprintf wrt ..plt
    mov rdi, r12
    lea rsi, [rsp + 1744]
    call queue_cstr_h
    mov rdi, r12
    call hg_emit_affects_now wrt ..plt
    jmp .done
.self:
    mov rdi, r12
    lea rsi, [rel sp2_witness_self]
    call queue_line_h
    jmp .done
.absent:
    lea rdi, [rsp + 1608]
    mov esi, 160
    lea rdx, [rel sp2_witness_absent]
    lea rcx, [rsp]
    xor eax, eax
    call snprintf wrt ..plt
    mov rdi, r12
    lea rsi, [rsp + 1608]
    call queue_line_h
    jmp .done
.twice:
    lea rdi, [rsp + 1608]
    mov esi, 160
    lea rdx, [rel sp2_witness_twice]
    lea rcx, [r14 + 48]
    xor eax, eax
    call snprintf wrt ..plt
    mov rdi, r12
    lea rsi, [rsp + 1608]
    call queue_line_h
.done:
    add rsp, 2040
    pop r15
    pop r14
    pop rbx
    CMD_UNALIGN
    ret

; --- dais pledge ------------------------------------------------------------
global hg_dais_pledge
hg_dais_pledge:
    mov r12, rdi
    CMD_ALIGN
    cmp qword [r12 + SESSION_ROOM], ROOM_DAIS
    jne .none
    lea rdi, [r12 + SESSION_FACTION]
    lea rsi, [rel sp2_none]
    call strcmp wrt ..plt
    jnz .settled
    lea rdi, [r12 + SESSION_FACTION]
    lea rsi, [rel sp2_front]
    mov edx, 16
    call strncpy wrt ..plt
    lea rdi, [r12 + SESSION_RACE]
    lea rsi, [rel sp2_elf]
    call strcasecmp wrt ..plt
    test eax, eax
    jz .hunted
    lea rdi, [r12 + SESSION_RACE]
    lea rsi, [rel sp2_dustkin]
    call strcasecmp wrt ..plt
    test eax, eax
    jnz .plain
.hunted:
    mov qword [r12 + SESSION_ASHSWORN], 1
    sub qword [r12 + SESSION_MORALITY], 40
    mov rdi, r12
    lea rsi, [rel sp2_dais_ash]
    call queue_cstr_h
    jmp .pledge_done
.plain:
    sub qword [r12 + SESSION_MORALITY], 25
    mov rdi, r12
    lea rsi, [rel sp2_dais_plain]
    call queue_line_h
.pledge_done:
    lea rdi, [r12 + SESSION_NAME]
    mov esi, DEED_PLEDGED
    call hg_add_deed_h
    xor edi, edi
    mov esi, -10
    call hg_grid_shift_tide wrt ..plt
    ; echo@0(160) shout@160(160) = 320; old 208-byte frame smashed ret on shout
    sub rsp, 320
    mov rdi, rsp
    mov esi, 160
    lea rdx, [rel sp2_pledge_echo]
    lea rcx, [r12 + SESSION_NAME]
    xor eax, eax
    call snprintf wrt ..plt
    lea rdi, [rel sp2_dais]
    lea rsi, [rel sp2_oath_kind]
    mov rdx, rsp
    call hg_grid_record_local_echo wrt ..plt
    mov rdi, r12
    call hg_store_save wrt ..plt
    lea rdi, [rsp + 160]
    mov esi, 160
    lea rdx, [rel sp2_pledge_shout]
    lea rcx, [r12 + SESSION_NAME]
    xor eax, eax
    call snprintf wrt ..plt
    mov edi, ROOM_DAIS
    lea rsi, [rsp + 160]
    lea rdx, [r12 + SESSION_NAME]
    call hg_deliver_room wrt ..plt
    mov rdi, r12
    call hg_moral_arc_now wrt ..plt
    mov rdi, r12
    call hg_emit_affects_now wrt ..plt
    mov rdi, r12
    lea rsi, [rel sp2_dais]
    call hg_emit_vitals_now wrt ..plt
    mov rdi, r12
    call hg_emit_room_actions_now wrt ..plt
    add rsp, 320
    CMD_UNALIGN
    ret
.none:
    mov rdi, r12
    lea rsi, [rel sp2_dais_none]
    call queue_line_h
    CMD_UNALIGN
    ret
.settled:
    mov rdi, r12
    lea rsi, [rel sp2_dais_settled]
    call queue_line_h
    CMD_UNALIGN
    ret
sp2_oath_kind: db "oath", 0

; --- defy -------------------------------------------------------------------
hg_cmd_defy:
    call setup_cmd
    CMD_ALIGN
    cmp qword [r12 + SESSION_ROOM], ROOM_DAIS
    jne .none
    lea rdi, [r12 + SESSION_FACTION]
    lea rsi, [rel sp2_front]
    call strcmp wrt ..plt
    jnz .none
    lea rdi, [r12 + SESSION_FACTION]
    lea rsi, [rel sp2_ally]
    mov edx, 16
    call strncpy wrt ..plt
    add qword [r12 + SESSION_MORALITY], 30
    cmp qword [r12 + SESSION_ASHSWORN], 0
    jne .ash
    mov rdi, r12
    lea rsi, [rel sp2_defy_plain]
    call queue_cstr_h
    jmp .defy_done
.ash:
    mov rdi, r12
    lea rsi, [rel sp2_defy_ash]
    call queue_cstr_h
.defy_done:
    lea rdi, [r12 + SESSION_NAME]
    mov esi, DEED_DEFECTED
    call hg_add_deed_h
    xor edi, edi
    mov esi, 10
    call hg_grid_shift_tide wrt ..plt
    sub rsp, 320
    mov rdi, rsp
    mov esi, 160
    lea rdx, [rel sp2_defy_echo]
    lea rcx, [r12 + SESSION_NAME]
    xor eax, eax
    call snprintf wrt ..plt
    lea rdi, [rel sp2_dais]
    lea rsi, [rel sp2_oath_kind]
    mov rdx, rsp
    call hg_grid_record_local_echo wrt ..plt
    mov rdi, r12
    call hg_store_save wrt ..plt
    lea rdi, [rsp + 160]
    mov esi, 160
    lea rdx, [rel sp2_defy_shout]
    lea rcx, [r12 + SESSION_NAME]
    xor eax, eax
    call snprintf wrt ..plt
    mov edi, ROOM_DAIS
    lea rsi, [rsp + 160]
    lea rdx, [r12 + SESSION_NAME]
    call hg_deliver_room wrt ..plt
    cmp qword [r12 + SESSION_STRAYED], 0
    je .moral
    cmp qword [r12 + SESSION_REDEEMED], 0
    jne .moral
    cmp qword [r12 + SESSION_ASHSWORN], 0
    jne .moral
    mov rax, [r12 + SESSION_MORALITY]
    cmp rax, REDEEM_CEIL
    jl .moral
    call resolve_return_h
    jmp .defy_emit
.moral:
    mov rdi, r12
    call hg_moral_arc_now wrt ..plt
.defy_emit:
    mov rdi, r12
    call hg_emit_affects_now wrt ..plt
    mov rdi, r12
    lea rsi, [rel sp2_dais]
    call hg_emit_vitals_now wrt ..plt
    mov rdi, r12
    call hg_emit_room_actions_now wrt ..plt
    add rsp, 320
    CMD_UNALIGN
    ret
.none:
    mov rdi, r12
    lea rsi, [rel sp2_defy_none]
    call queue_line_h
    CMD_UNALIGN
    ret

